-- Search analytics indexes for faster queries
CREATE INDEX IF NOT EXISTS idx_search_analytics_created_at 
  ON search_analytics(created_at);

CREATE INDEX IF NOT EXISTS idx_search_analytics_query 
  ON search_analytics(query);

-- Composite index for analytics queries
CREATE INDEX IF NOT EXISTS idx_search_analytics_date_query 
  ON search_analytics(created_at, query);

-- Index for ICD description search
CREATE INDEX IF NOT EXISTS idx_icd_codes_description 
  ON icd_codes(description(100));

